        .dashboard-loading p {
          color: #64748b;
          font-size: 16px;
        }

        /* Error State */
        .dashboard-error {
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          min-height: 100vh;
          padding: 40px;
          text-align: center;
          background: #f8fafc;
        }

        .error-icon {
          font-size: 60px;
          margin-bottom: 20px;
        }

        .dashboard-error h3 {
          color: #dc2626;
          margin-bottom: 10px;
        }

        .dashboard-error p {
          color: #64748b;
          margin-bottom: 30px;
          max-width: 500px;
        }

        .retry-btn {
          display: flex;
          align-items: center;
          gap: 8px;
          padding: 10px 24px;
          background: #3b82f6;
          color: white;
          border: none;
          border-radius: 8px;
          font-weight: 600;
          cursor: pointer;
          transition: background 0.2s;
        }

        .retry-btn:hover {
          background: #2563eb;
        }

        .refresh-icon {
          width: 18px;
          height: 18px;
          animation: spin 1s linear infinite;
        }

        /* Sidebar */
        .dashboard-sidebar {
          width: 280px;
          background: white;
          border-right: 1px solid #e2e8f0;
          display: flex;
          flex-direction: column;
          position: fixed;
          height: 100vh;
          z-index: 100;
        }

        .sidebar-header {
          padding: 24px;
          border-bottom: 1px solid #e2e8f0;
        }

        .sidebar-logo {
          display: flex;
          align-items: center;
          gap: 12px;
          margin-bottom: 30px;
        }

        .logo-icon {
          font-size: 32px;
        }

        .sidebar-logo h2 {
          margin: 0;
          font-size: 20px;
          color: #1e293b;
        }

        .sidebar-user {
          display: flex;
          align-items: center;
          gap: 12px;
        }

        .user-avatar {
          width: 56px;
          height: 56px;
          border-radius: 12px;
          overflow: hidden;
          background: #f1f5f9;
          display: flex;
          align-items: center;
          justify-content: center;
        }

        .user-avatar img {
          width: 100%;
          height: 100%;
          object-fit: cover;
        }

        .user-info h4 {
          margin: 0;
          font-size: 16px;
          color: #1e293b;
        }

        .user-info p {
          margin: 4px 0;
          font-size: 14px;
          color: #64748b;
        }

        .user-badge {
          display: inline-block;
          padding: 4px 8px;
          background: #dbeafe;
          color: #1d4ed8;
          border-radius: 6px;
          font-size: 12px;
          font-weight: 600;
        }

        .sidebar-nav {
          flex: 1;
          padding: 20px;
          display: flex;
          flex-direction: column;
          gap: 4px;
        }

        .nav-item {
          display: flex;
          align-items: center;
          gap: 12px;
          padding: 12px 16px;
          background: none;
          border: none;
          border-radius: 8px;
          color: #64748b;
          font-size: 15px;
          font-weight: 500;
          cursor: pointer;
          transition: all 0.2s;
          text-align: left;
        }

        .nav-item:hover {
          background: #f1f5f9;
          color: #475569;
        }

        .nav-item.active {
          background: #3b82f6;
          color: white;
        }

        .nav-icon {
          font-size: 20px;
        }

        .nav-divider {
          height: 1px;
          background: #e2e8f0;
          margin: 20px 0;
        }

        .sidebar-footer {
          padding: 20px;
          border-top: 1px solid #e2e8f0;
        }

        .chatbot-promo {
          display: flex;
          align-items: center;
          gap: 12px;
          padding: 12px;
          background: #f0f9ff;
          border-radius: 8px;
          border: 1px solid #bae6fd;
        }

        .promo-icon {
          font-size: 24px;
        }

        .promo-text {
          display: flex;
          flex-direction: column;
        }

        .promo-text strong {
          font-size: 14px;
          color: #0c4a6e;
        }

        .promo-text small {
          font-size: 12px;
          color: #0369a1;
        }

        /* Main Content */
        .dashboard-main {
          flex: 1;
          margin-left: 280px;
          min-height: 100vh;
          display: flex;
          flex-direction: column;
        }

        .main-header {
          padding: 20px 32px;
          background: white;
          border-bottom: 1px solid #e2e8f0;
          display: flex;
          justify-content: space-between;
          align-items: center;
        }

        .header-left h1 {
          margin: 0;
          font-size: 24px;
          color: #1e293b;
        }

        .breadcrumb {
          margin-top: 4px;
          font-size: 14px;
          color: #64748b;
        }

        .header-right {
          display: flex;
          align-items: center;
          gap: 16px;
        }

        .header-btn {
          width: 40px;
          height: 40px;
          border-radius: 8px;
          border: 1px solid #e2e8f0;
          background: white;
          display: flex;
          align-items: center;
          justify-content: center;
          cursor: pointer;
          transition: all 0.2s;
          position: relative;
        }

        .header-btn:hover {
          background: #f8fafc;
          border-color: #cbd5e1;
        }

        .notification-badge {
          position: absolute;
          top: -4px;
          right: -4px;
          background: #ef4444;
          color: white;
          width: 18px;
          height: 18px;
          border-radius: 50%;
          font-size: 10px;
          display: flex;
          align-items: center;
          justify-content: center;
        }

        .refresh-btn {
          animation: spin 1s linear infinite;
        }

        .header-user .greeting {
          font-size: 14px;
          color: #475569;
          font-weight: 500;
        }

        /* Stats Grid */
        .stats-grid {
          display: grid;
          grid-template-columns: repeat(4, 1fr);
          gap: 20px;
          padding: 24px 32px;
        }

        .stat-card {
          background: white;
          border-radius: 12px;
          padding: 20px;
          display: flex;
          align-items: center;
          gap: 16px;
          border: 1px solid #e2e8f0;
          transition: transform 0.2s, box-shadow 0.2s;
        }

        .stat-card:hover {
          transform: translateY(-2px);
          box-shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
        }

        .stat-icon {
          width: 60px;
          height: 60px;
          border-radius: 12px;
          display: flex;
          align-items: center;
          justify-content: center;
        }

        .stat-icon.gpa {
          background: #fef3c7;
          color: #d97706;
        }

        .stat-icon.credits {
          background: #dbeafe;
          color: #1d4ed8;
        }

        .stat-icon.semester {
          background: #dcfce7;
          color: #16a34a;
        }

        .stat-icon.progress {
          background: #f3e8ff;
          color: #7c3aed;
        }

        .progress-ring {
          position: relative;
          display: flex;
          align-items: center;
          justify-content: center;
        }

        .progress-bg {
          stroke: #e2e8f0;
        }

        .progress-fill {
          stroke: #8b5cf6;
          stroke-linecap: round;
          transform: rotate(-90deg);
          transform-origin: 50% 50%;
          transition: stroke-dasharray 0.5s;
        }

        .progress-ring span {
          position: absolute;
          font-size: 14px;
          font-weight: 600;
          color: #7c3aed;
        }

        .stat-content h3 {
          margin: 0;
          font-size: 14px;
          color: #64748b;
          font-weight: 500;
        }

        .stat-value {
          font-size: 24px;
          font-weight: 700;
          color: #1e293b;
          margin: 4px 0;
        }

        .stat-label {
          font-size: 13px;
          color: #94a3b8;
        }

        /* Content Area */
        .content-area {
          flex: 1;
          padding: 0 32px 32px;
          display: grid;
          grid-template-columns: 1fr 400px;
          gap: 24px;
        }

        .content-card {
          background: white;
          border-radius: 12px;
          padding: 24px;
          border: 1px solid #e2e8f0;
          margin-bottom: 24px;
        }

        .card-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 20px;
        }

        .card-header h3 {
          margin: 0;
          font-size: 18px;
          color: #1e293b;
        }

        .card-action {
          padding: 6px 12px;
          background: #f1f5f9;
          border: 1px solid #cbd5e1;
          border-radius: 6px;
          font-size: 14px;
          color: #475569;
          cursor: pointer;
          transition: all 0.2s;
        }

        .card-action:hover {
          background: #e2e8f0;
        }

        .badge {
          padding: 4px 10px;
          background: #dbeafe;
          color: #1d4ed8;
          border-radius: 20px;
          font-size: 12px;
          font-weight: 600;
        }

        /* Semester Metrics */
        .semester-metrics {
          display: grid;
          grid-template-columns: repeat(2, 1fr);
          gap: 20px;
          margin-bottom: 20px;
        }

        .metric {
          padding: 16px;
          background: #f8fafc;
          border-radius: 8px;
        }

        .metric label {
          display: block;
          font-size: 14px;
          color: #64748b;
          margin-bottom: 8px;
        }

        .metric-value {
          font-size: 24px;
          font-weight: 700;
          color: #1e293b;
        }

        .semester-period {
          display: flex;
          align-items: center;
          gap: 8px;
          color: #64748b;
          font-size: 14px;
        }

        /* Courses List */
        .courses-list {
          display: flex;
          flex-direction: column;
          gap: 12px;
        }

        .empty-state {
          text-align: center;
          padding: 40px;
          color: #94a3b8;
          font-size: 14px;
        }

        .course-item {
          padding: 16px;
          border: 1px solid #e2e8f0;
          border-radius: 8px;
          transition: all 0.2s;
        }

        .course-item:hover {
          border-color: #cbd5e1;
          background: #f8fafc;
        }

        .course-header {
          display: flex;
          justify-content: space-between;
          align-items: flex-start;
          margin-bottom: 8px;
        }

        .course-code {
          margin: 0;
          font-size: 16px;
          color: #1e293b;
          font-weight: 600;
        }

        .course-name {
          margin: 4px 0 0;
          font-size: 14px;
          color: #64748b;
        }

        .grade-badge {
          padding: 4px 10px;
          border-radius: 6px;
          font-size: 14px;
          font-weight: 600;
        }

        .grade-badge.a { background: #dcfce7; color: #166534; }
        .grade-badge.b { background: #fef3c7; color: #92400e; }
        .grade-badge.c { background: #fde68a; color: #854d0e; }
        .grade-badge.d { background: #fed7aa; color: #9a3412; }
        .grade-badge.f { background: #fee2e2; color: #991b1b; }
        .grade-badge.none { background: #f1f5f9; color: #64748b; }

        .course-details {
          display: flex;
          justify-content: space-between;
          align-items: center;
          font-size: 13px;
        }

        .course-credit {
          color: #475569;
        }

        .course-status {
          padding: 4px 8px;
          border-radius: 6px;
          font-size: 12px;
          font-weight: 600;
        }

        .course-status.enrolled { background: #dbeafe; color: #1d4ed8; }
        .course-status.completed { background: #dcfce7; color: #166534; }
        .course-status.dropped { background: #fee2e2; color: #991b1b; }

        /* Quick Actions */
        .quick-actions-grid {
          display: grid;
          grid-template-columns: repeat(3, 1fr);
          gap: 12px;
        }

        .quick-action {
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          padding: 16px 8px;
          background: #f8fafc;
          border: 1px solid #e2e8f0;
          border-radius: 8px;
          cursor: pointer;
          transition: all 0.2s;
          gap: 8px;
        }

        .quick-action:hover {
          background: #e2e8f0;
          transform: translateY(-2px);
        }

        .action-icon {
          font-size: 24px;
        }

        .quick-action span:last-child {
          font-size: 12px;
          color: #475569;
          font-weight: 500;
          text-align: center;
        }

        /* Semesters Table */
        .semesters-table {
          border: 1px solid #e2e8f0;
          border-radius: 8px;
          overflow: hidden;
        }

        .table-header {
          display: grid;
          grid-template-columns: 1fr 1fr 1fr 1fr;
          padding: 12px 16px;
          background: #f8fafc;
          font-weight: 600;
          color: #475569;
          font-size: 14px;
          border-bottom: 1px solid #e2e8f0;
        }

        .table-row {
          display: grid;
          grid-template-columns: 1fr 1fr 1fr 1fr;
          padding: 12px 16px;
          border-bottom: 1px solid #e2e8f0;
          font-size: 14px;
          align-items: center;
        }

        .table-row:last-child {
          border-bottom: none;
        }

        .status-badge {
          padding: 4px 10px;
          border-radius: 20px;
          font-size: 12px;
          font-weight: 600;
        }

        .status-badge.completed { background: #dcfce7; color: #166534; }
        .status-badge.in-progress { background: #dbeafe; color: #1d4ed8; }
        .status-badge.failed { background: #fee2e2; color: #991b1b; }

        .gpa-value {
          font-weight: 600;
          color: #1e293b;
        }

        /* Chatbot Help */
        .chatbot-help {
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          color: white;
        }

        .chatbot-help .card-header h3 {
          color: white;
        }

        .help-content {
          display: flex;
          flex-direction: column;
          align-items: center;
          text-align: center;
          gap: 16px;
        }

        .help-icon {
          font-size: 48px;
        }

        .help-content p {
          margin: 0;
          font-size: 14px;
          opacity: 0.9;
        }

        .help-list {
          text-align: left;
          padding: 0;
          margin: 0;
          list-style: none;
          width: 100%;
        }

        .help-list li {
          padding: 8px 0;
          font-size: 13px;
          border-bottom: 1px solid rgba(255, 255, 255, 0.1);
        }

        .help-list li:last-child {
          border-bottom: none;
        }

        /* Footer */
        .dashboard-footer {
          padding: 20px 32px;
          background: white;
          border-top: 1px solid #e2e8f0;
          display: flex;
          justify-content: space-between;
          align-items: center;
          color: #64748b;
          font-size: 14px;
        }

        .footer-links {
          display: flex;
          gap: 24px;
        }

        .footer-links a {
          color: #64748b;
          text-decoration: none;
          transition: color 0.2s;
        }

        .footer-links a:hover {
          color: #3b82f6;
        }

        /* Animations */
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }

        /* Responsive */
        @media (max-width: 1200px) {
          .stats-grid {
            grid-template-columns: repeat(2, 1fr);
          }

          .content-area {
            grid-template-columns: 1fr;
          }

          .quick-actions-grid {
            grid-template-columns: repeat(6, 1fr);
          }
        }

        @media (max-width: 768px) {
          .dashboard-sidebar {
            width: 100%;
            height: auto;
                position: relative;
                margin-bottom: 20px;
              }

              .dashboard-main {
                margin-left: 0;
              }

              .stats-grid {
                grid-template-columns: 1fr;
              }

              .main-header {
                flex-direction: column;
                gap: 16px;
                text-align: center;
              }

              .quick-actions-grid {
                grid-template-columns: repeat(2, 1fr);
              }

              .semester-metrics {
                grid-template-columns: 1fr;
              }

              .table-header, .table-row {
                grid-template-columns: 1fr 1fr;
              }

              .dashboard-footer {
                flex-direction: column;
                gap: 16px;
                text-align: center;
              }
            }

            @media (max-width: 480px) {
              .content-card {
