// src/pages/StudentDashboard.jsx - COMPLETE VERSION
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Loader2, User, Calendar, BookOpen, Award, Bell, Settings } from 'lucide-react';
import ChatbotInterface from '../components/ChatbotInterface';

// Create axios instance
const api = axios.create({
  baseURL: 'http://localhost:65000',
  withCredentials: true,
  headers: {
    'Content-Type': 'application/json'
  }
});

const StudentDashboard = () => {
  const [payload, setPayload] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showAllSemesters, setShowAllSemesters] = useState(false);
  const [activeTab, setActiveTab] = useState('overview');

  useEffect(() => {
    loadDashboard();
  }, []);

  const loadDashboard = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await api.get('/api/students/getStudentDashboard');
      setPayload(res.data);
      
      if (res.data.student) {
        const studentData = {
          _id: res.data.student._id,
          studentId: res.data.student.studentId,
          firstName: res.data.student.name?.firstName || '',
          lastName: res.data.student.name?.lastName || '',
          fullName: res.data.student.name?.fullName || '',
          universityEmail: res.data.student.universityEmail,
          role: 'student',
          profilePic: res.data.student.photoPath || null
        };
        localStorage.setItem('userInfo', JSON.stringify(studentData));
      }
    } catch (err) {
      console.error('Dashboard load error:', err);
      setError(err.response?.data?.message || 'Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="dashboard-loading">
        <Loader2 className="spinner" />
        <p>Loading your dashboard...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="dashboard-error">
        <div className="error-icon">⚠️</div>
        <h3>Error Loading Dashboard</h3>
        <p>{error}</p>
        <button className="retry-btn" onClick={loadDashboard}>
          <Loader2 className="refresh-icon" />
          Retry
        </button>
      </div>
    );
  }

  if (!payload) {
    return (
      <div className="dashboard-empty">
        <p>No data available</p>
        <button onClick={loadDashboard}>Load Dashboard</button>
      </div>
    );
  }

  const { student, academicProgress } = payload;
  const current = academicProgress.currentSemesterDetails || {};
  const percentProgress = Math.min(
    100,
    Math.round((academicProgress.totalCreditsEarned / Math.max(1, academicProgress.totalCreditsRequired)) * 100)
  );

  return (
    <div className="student-dashboard">
      {/* Chatbot */}
      <ChatbotInterface />
      
      {/* Sidebar */}
      <div className="dashboard-sidebar">
        <div className="sidebar-header">
          <div className="sidebar-logo">
            <div className="logo-icon">🎓</div>
            <h2>Superior ERP</h2>
          </div>
          <div className="sidebar-user">
            <div className="user-avatar">
              {student.photoPath ? (
                <img src={`http://localhost:65000/${student.photoPath}`} alt={student.name?.fullName} />
              ) : (
                <User size={40} />
              )}
            </div>
            <div className="user-info">
              <h4>{student.name?.fullName || 'Student'}</h4>
              <p>{student.studentId}</p>
              <span className="user-badge">{student.role || 'Student'}</span>
            </div>
          </div>
        </div>
        
        <nav className="sidebar-nav">
          <button 
            className={`nav-item ${activeTab === 'overview' ? 'active' : ''}`}
            onClick={() => setActiveTab('overview')}
          >
            <div className="nav-icon">📊</div>
            <span>Overview</span>
          </button>
          
          <button 
            className={`nav-item ${activeTab === 'courses' ? 'active' : ''}`}
            onClick={() => setActiveTab('courses')}
          >
            <div className="nav-icon">📚</div>
            <span>Courses</span>
          </button>
          
          <button 
            className={`nav-item ${activeTab === 'attendance' ? 'active' : ''}`}
            onClick={() => setActiveTab('attendance')}
          >
            <div className="nav-icon">📅</div>
            <span>Attendance</span>
          </button>
          
          <button 
            className={`nav-item ${activeTab === 'grades' ? 'active' : ''}`}
            onClick={() => setActiveTab('grades')}
          >
            <div className="nav-icon">🎯</div>
            <span>Grades</span>
          </button>
          
          <button 
            className={`nav-item ${activeTab === 'fees' ? 'active' : ''}`}
            onClick={() => setActiveTab('fees')}
          >
            <div className="nav-icon">💰</div>
            <span>Fees</span>
          </button>
          
          <div className="nav-divider"></div>
          
          <button 
            className={`nav-item ${activeTab === 'profile' ? 'active' : ''}`}
            onClick={() => setActiveTab('profile')}
          >
            <div className="nav-icon">👤</div>
            <span>Profile</span>
          </button>
          
          <button 
            className={`nav-item ${activeTab === 'settings' ? 'active' : ''}`}
            onClick={() => setActiveTab('settings')}
          >
            <div className="nav-icon">⚙️</div>
            <span>Settings</span>
          </button>
        </nav>
        
        <div className="sidebar-footer">
          <div className="chatbot-promo">
            <div className="promo-icon">💬</div>
            <div className="promo-text">
              <strong>ERP Assistant</strong>
              <small>Ask me anything!</small>
            </div>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="dashboard-main">
        {/* Header */}
        <header className="main-header">
          <div className="header-left">
            <h1>Student Dashboard</h1>
            <div className="breadcrumb">Home / Dashboard</div>
          </div>
          
          <div className="header-right">
            <button className="header-btn notification-btn">
              <Bell size={20} />
              <span className="notification-badge">3</span>
            </button>
            
            <button className="header-btn refresh-btn" onClick={loadDashboard}>
              <Loader2 size={20} />
            </button>
            
            <div className="header-user">
              <span className="greeting">Hello, {student.name?.firstName || 'Student'}!</span>
            </div>
          </div>
        </header>

        {/* Stats Cards */}
        <div className="stats-grid">
          <div className="stat-card">
            <div className="stat-icon gpa">
              <Award />
            </div>
            <div className="stat-content">
              <h3>CGPA</h3>
              <div className="stat-value">{academicProgress.cumulativeGPA || '-'}</div>
              <div className="stat-label">Cumulative</div>
            </div>
          </div>
          
          <div className="stat-card">
            <div className="stat-icon credits">
              <BookOpen />
            </div>
            <div className="stat-content">
              <h3>Credits</h3>
              <div className="stat-value">{academicProgress.totalCreditsEarned}/{academicProgress.totalCreditsRequired}</div>
              <div className="stat-label">{percentProgress}% Complete</div>
            </div>
          </div>
          
          <div className="stat-card">
            <div className="stat-icon semester">
              <Calendar />
            </div>
            <div className="stat-content">
              <h3>Semester</h3>
              <div className="stat-value">{academicProgress.currentSemester || 'N/A'}</div>
              <div className="stat-label">Current</div>
            </div>
          </div>
          
          <div className="stat-card">
            <div className="stat-icon progress">
              <div className="progress-ring">
                <svg width="60" height="60">
                  <circle cx="30" cy="30" r="25" strokeWidth="8" fill="transparent" className="progress-bg" />
                  <circle cx="30" cy="30" r="25" strokeWidth="8" fill="transparent" className="progress-fill" 
                    strokeDasharray={`${percentProgress * 1.57} 157`} />
                </svg>
                <span>{percentProgress}%</span>
              </div>
            </div>
            <div className="stat-content">
              <h3>Progress</h3>
              <div className="stat-value">{academicProgress.completionPercentage || percentProgress}%</div>
              <div className="stat-label">Degree Completion</div>
            </div>
          </div>
        </div>

        {/* Main Content Area */}
        <div className="content-area">
          {/* Left Column */}
          <div className="content-left">
            {/* Current Semester */}
            <div className="content-card">
              <div className="card-header">
                <h3>Current Semester - #{academicProgress.currentSemester}</h3>
                <button className="card-action" onClick={() => setShowAllSemesters(!showAllSemesters)}>
                  {showAllSemesters ? 'Hide' : 'Show'} All
                </button>
              </div>
              
              <div className="semester-metrics">
                <div className="metric">
                  <label>Semester GPA</label>
                  <div className="metric-value">{current.semesterGPA || '-'}</div>
                </div>
                <div className="metric">
                  <label>Credits Attempted</label>
                  <div className="metric-value">{current.creditsAttempted || 0}</div>
                </div>
                <div className="metric">
                  <label>Credits Earned</label>
                  <div className="metric-value">{current.creditsEarned || 0}</div>
                </div>
                <div className="metric">
                  <label>Quality Points</label>
                  <div className="metric-value">{current.qualityPoints || 0}</div>
                </div>
              </div>
              
              {current.startDate && (
                <div className="semester-period">
                  <Calendar size={16} />
                  <span>
                    {new Date(current.startDate).toLocaleDateString()} - {new Date(current.endDate).toLocaleDateString()}
                  </span>
                </div>
              )}
            </div>

            {/* Courses */}
            <div className="content-card">
              <div className="card-header">
                <h3>Enrolled Courses</h3>
                <span className="badge">{current.courses?.length || 0} courses</span>
              </div>
              
              <div className="courses-list">
                {(current.courses || []).length === 0 ? (
                  <div className="empty-state">No courses enrolled this semester</div>
                ) : (
                  current.courses.map((course, idx) => (
                    <div key={idx} className="course-item">
                      <div className="course-header">
                        <div>
                          <h4 className="course-code">{course.courseCode || 'N/A'}</h4>
                          <p className="course-name">{course.courseName || 'Untitled Course'}</p>
                        </div>
                        <div className="course-grade">
                          <span className={`grade-badge ${course.grade?.toLowerCase() || 'none'}`}>
                            {course.grade || '-'}
                          </span>
                        </div>
                      </div>
                      <div className="course-details">
                        <span className="course-credit">Credits: {course.creditsEarned || 0}</span>
                        <span className={`course-status ${course.status?.toLowerCase()}`}>
                          {course.status || 'N/A'}
                        </span>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>

          {/* Right Column */}
          <div className="content-right">
            {/* Quick Actions */}
            <div className="content-card">
              <div className="card-header">
                <h3>Quick Actions</h3>
              </div>
              <div className="quick-actions-grid">
                <button className="quick-action">
                  <span className="action-icon">📅</span>
                  <span>View Timetable</span>
                </button>
                <button className="quick-action">
                  <span className="action-icon">💰</span>
                  <span>Pay Fees</span>
                </button>
                <button className="quick-action">
                  <span className="action-icon">📝</span>
                  <span>View Results</span>
                </button>
                <button className="quick-action">
                  <span className="action-icon">📊</span>
                  <span>Attendance Report</span>
                </button>
                <button className="quick-action">
                  <span className="action-icon">📚</span>
                  <span>Course Materials</span>
                </button>
                <button className="quick-action">
                  <span className="action-icon">🎓</span>
                  <span>Apply Leave</span>
                </button>
              </div>
            </div>

            {/* All Semesters (Collapsible) */}
            {showAllSemesters && (
              <div className="content-card">
                <div className="card-header">
                  <h3>All Semesters</h3>
                </div>
                <div className="semesters-table">
                  <div className="table-header">
                    <div>Semester</div>
                    <div>Status</div>
                    <div>GPA</div>
                    <div>Credits</div>
                  </div>
                  {(academicProgress.allSemesters || []).map((sem, i) => (
                    <div key={i} className="table-row">
                      <div>Semester {sem.semesterNumber}</div>
                      <div>
                        <span className={`status-badge ${sem.status?.toLowerCase()}`}>
                          {sem.status}
                        </span>
                      </div>
                      <div className="gpa-value">{sem.semesterGPA}</div>
                      <div>{sem.creditsEarned}/{sem.creditsAttempted}</div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Chatbot Help */}
            <div className="content-card chatbot-help">
              <div className="card-header">
                <h3>Need Help?</h3>
              </div>
              <div className="help-content">
                <div className="help-icon">💬</div>
                <p>Click the chat icon in the bottom right to ask the ERP Assistant about:</p>
                <ul className="help-list">
                  <li>Fees and payments</li>
                  <li>Attendance details</li>
                  <li>Exam schedules</li>
                  <li>Course information</li>
                  <li>And much more!</li>
                </ul>
              </div>
            </div>
          </div>
        </div>

        {/* Footer */}
        <footer className="dashboard-footer">
          <p>Superior University Student Portal © {new Date().getFullYear()}</p>
          <div className="footer-links">
            <a href="#">Privacy Policy</a>
            <a href="#">Terms of Service</a>
            <a href="#">Help Center</a>
            <a href="#">Contact Support</a>
          </div>
        </footer>
      </div>

      {/* CSS Styles */}
      <style jsx>{`
