          color: #1e293b;
          margin: 4px 0;
        }

        .stat-label {
          font-size: 13px;
          color: #94a3b8;
        }

        /* Content Area */
        .content-area {
          flex: 1;
          padding: 0 32px 32px;
          display: grid;
          grid-template-columns: 1fr 400px;
          gap: 24px;
