        .chatbot-help {
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          color: white;
        }

        .chatbot-help .card-header h3 {
          color: white;
        }

        .help-content {
          display: flex;
          flex-direction: column;
          align-items: center;
          text-align: center;
          gap: 16px;
        }

        .help-icon {
          font-size: 48px;
        }

        .help-content p {
          margin: 0;
          font-size: 14px;
          opacity: 0.9;
        }

        .help-list {
          text-align: left;
          padding: 0;
          margin: 0;
          list-style: none;
          width: 100%;
        }

        .help-list li {
          padding: 8px 0;
          font-size: 13px;
          border-bottom: 1px solid rgba(255, 255, 255, 0.1);
        }

        .help-list li:last-child {
          border-bottom: none;
        }

        /* Footer */
        .dashboard-footer {
          padding: 20px 32px;
          background: white;
          border-top: 1px solid #e2e8f0;
          display: flex;
          justify-content: space-between;
          align-items: center;
          color: #64748b;
          font-size: 14px;
        }

        .footer-links {
          display: flex;
          gap: 24px;
        }

        .footer-links a {
          color: #64748b;
          text-decoration: none;
          transition: color 0.2s;
        }

        .footer-links a:hover {
          color: #3b82f6;
        }

        /* Animations */
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }

        /* Responsive */
        @media (max-width: 1200px) {
          .stats-grid {
            grid-template-columns: repeat(2, 1fr);
          }
          
          .content-area {
            grid-template-columns: 1fr;
          }
          
          .quick-actions-grid {
            grid-template-columns: repeat(6, 1fr);
          }
        }

        @media (max-width: 768px) {
          .dashboard-sidebar {
            width: 100%;
            height: auto;
                position: relative;
                margin-bottom: 20px;
              }
              
              .dashboard-main {
                margin-left: 0;
              }
              
              .stats-grid {
                grid-template-columns: 1fr;
              }
              
              .main-header {
                flex-direction: column;
                gap: 16px;
                text-align: center;
              }
              
              .quick-actions-grid {
                grid-template-columns: repeat(2, 1fr);
              }
              
              .semester-metrics {
                grid-template-columns: 1fr;
              }
              
              .table-header, .table-row {
                grid-template-columns: 1fr 1fr;
              }
              
              .dashboard-footer {
                flex-direction: column;
                gap: 16px;
                text-align: center;
              }
            }
            
            @media (max-width: 480px) {
              .content-card {
                padding: 16px;
              }
              
              .stats-grid, .content-area {
                padding-left: 16px;
                padding-right: 16px;
              }
              
              .quick-actions-grid {
                grid-template-columns: 1fr;
              }
            }
          `}</style>
        </div>
      );
    };
    
    export default StudentDashboard;
